                        <input 
                            type="checkbox" 
                            className="w-6 h-6 text-brand-secondary rounded accent-brand-secondary"
                            checked={settings.enableDelayAlerts}
                            onChange={e => setSettings({...settings, enableDelayAlerts: e.target.checked})}
