                 {/* Incident Settings */}
                 <div className={`flex items-center justify-between border-t pt-6 ${!settings.masterEnabled ? 'opacity-50 pointer-events-none' : ''}`}>
                     <div>
                         <h3 className="font-bold text-gray-700">Alertes Incidents (Kiosque)</h3>
